            4'd5: begin step_addr = 8'h14; step_data = {7'd0, input_h_rom, 7'd0, input_w_rom}; end
            4'd6: begin step_addr = 8'h18; step_data = {7'd0, output_h_rom, 7'd0, output_w_rom}; end
            4'd7: begin step_addr = 8'h1C; step_data = {12'd0, weight_base_word_rom}; end
            4'd8: begin step_addr = 8'h20; step_data = {16'd0, bias_base_word_rom}; end
            4'd9: begin step_addr = 8'h24; step_data = scale_mult_rom; end
            4'd10: begin step_addr = 8'h28; step_data = {18'd0, zero_point_rom, scale_shift_rom}; end
            4'd11: begin step_addr = 8'h34; step_data = {16'd0, act_in_base_word_rom}; end
            4'd12: begin step_addr = 8'h38; step_data = {16'd0, act_out_base_word_rom}; end
            default: begin step_addr = 8'h00; step_data = 32'd0; end
        endcase
    end

    // ------------------------------------------------------------
    // FSM next-state logic
    // ------------------------------------------------------------
    always @(*) begin
        next_state = state;
        case (state)
            S_IDLE:        if (start) next_state = S_WRITE;
            // S_WRITE asserts AW and W in the same cycle. A correct AXI4-Lite
            // slave fires the handshake when (awvalid & awready & wvalid & wready)
            // are all true in one cycle. aw_acked_r / w_acked_r let the slave
            // return the two ready signals in different cycles too.
            S_WRITE:
                if ((aw_acked_r || (s_axil_awvalid && s_axil_awready)) &&
                    (w_acked_r  || (s_axil_wvalid  && s_axil_wready)))
                    next_state = S_WRITE_RESP;
            S_WRITE_RESP:  if (s_axil_bvalid)  next_state = S_NEXT_STEP;
            // Fix 11: after the final config write, wait until the input
            // loader bridge for the current dispatch has finished filling
            // the activation BRAM. current_loaded comes from a wrapper-
            // side mux over per-dispatch `loaded` signals.
            S_NEXT_STEP:   next_state = (write_step == LAST_STEP) ? S_WAIT_LOAD : S_WRITE;
            S_WAIT_LOAD:   if (current_loaded) next_state = S_PULSE_START;
            S_PULSE_START: next_state = S_WAIT_DONE;
            // Fix 14: between dispatches, wait in S_WAIT_DRAIN until the
            // engine_output_fifo has been fully drained by this dispatch's
            // bridge. Otherwise dispatch N+1's writes would interleave with
            // N's outputs still in the FIFO. spatial_stall=0 in this state
            // so the spatial chain runs and drains the bridge → FIFO →
            // downstream relu/add → next input_loader path.
            S_WAIT_DONE:   if (engine_done) next_state = S_WAIT_DRAIN;
            S_WAIT_DRAIN:  if (current_drain_complete) next_state = S_NEXT_DISP;
            S_NEXT_DISP:   next_state = (dispatch_idx == LAST_DISPATCH) ? S_DONE : S_WRITE;
            S_DONE:        next_state = S_DONE;
            default:       next_state = S_IDLE;
        endcase
    end

    // ------------------------------------------------------------
    // Sequential state + counters
    // ------------------------------------------------------------
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state        <= S_IDLE;
            dispatch_idx <= {4{1'b0}};
            write_step   <= {4{1'b0}};
            aw_acked_r   <= 1'b0;
            w_acked_r    <= 1'b0;
        end else begin
            state <= next_state;
            if (state == S_IDLE && start) begin
                dispatch_idx <= {4{1'b0}};
                write_step   <= {4{1'b0}};
            end
            if (state == S_NEXT_STEP) begin
                if (write_step == LAST_STEP) begin
                    write_step <= {4{1'b0}};
                end else begin
                    write_step <= write_step + 1'b1;
                end
            end
            if (state == S_NEXT_DISP && dispatch_idx != LAST_DISPATCH) begin
                dispatch_idx <= dispatch_idx + 1'b1;
            end
            // Latch per-channel handshake acks while in S_WRITE; clear
            // when leaving S_WRITE so the next register write starts fresh.
            if (state == S_WRITE) begin
                if (s_axil_awvalid && s_axil_awready) aw_acked_r <= 1'b1;
                if (s_axil_wvalid  && s_axil_wready)  w_acked_r  <= 1'b1;
            end else begin
                aw_acked_r <= 1'b0;
                w_acked_r  <= 1'b0;
            end
        end
    end

    // ------------------------------------------------------------
    // Output assignments
    // ------------------------------------------------------------
    always @(*) begin
        s_axil_awvalid          = 1'b0;
        s_axil_awaddr           = 8'd0;
        s_axil_wvalid           = 1'b0;
        s_axil_wdata            = 32'd0;
        s_axil_wstrb            = 4'b1111;
        s_axil_bready           = 1'b0;
        engine_start            = 1'b0;
        done                    = 1'b0;
        spatial_stall           = 1'b0;
        engine_output_ready     = 1'b0;
        input_bank_sel          = input_bank_rom;
        output_bank_sel         = output_bank_rom;
        skip_bank_reserved_mask = skip_mask_rom;

        case (state)
            S_IDLE: begin
                spatial_stall = 1'b0;
            end
            // Single S_WRITE: drive AW and W simultaneously. Hold each
            // valid line high until its respective handshake fires, then
            // (per the FSM next-state logic) wait for the other before
            // transitioning to S_WRITE_RESP.
            S_WRITE: begin
                s_axil_awvalid = ~aw_acked_r;
                s_axil_awaddr  = step_addr;
                s_axil_wvalid  = ~w_acked_r;
                s_axil_wdata   = step_data;
                s_axil_wstrb   = 4'b1111;
                spatial_stall  = 1'b1;
            end
            S_WRITE_RESP: begin
                s_axil_bready = 1'b1;
                spatial_stall = 1'b1;
            end
            S_NEXT_STEP: begin
                spatial_stall = 1'b1;
            end
            S_WAIT_LOAD: begin
                spatial_stall = 1'b0; // let the spatial chain keep filling the loader BRAM
            end
            S_PULSE_START: begin
                // Fix 11: CONTROL.start AXI write is removed; this pin is now
                // the SOLE engine-start trigger. We reach here only after
                // S_WAIT_LOAD has observed current_loaded, so the activation
                // BRAM is guaranteed populated for this dispatch.
                engine_start  = 1'b1;
                spatial_stall = 1'b1;
            end
            S_WAIT_DONE: begin
                spatial_stall = 1'b1;
            end
            S_WAIT_DRAIN: begin
                // Fix 14: chain MUST run so the bridge can drain the
                // engine_output_fifo and feed downstream relu/add layers.
                spatial_stall = 1'b0;
            end
            S_NEXT_DISP: begin
                spatial_stall       = 1'b1;
                engine_output_ready = 1'b1;
            end
            S_DONE: begin
                done                = 1'b1;
            end
            default: begin
                spatial_stall = 1'b0;
            end
        endcase
    end

    wire _unused_s_axil_bresp = |s_axil_bresp;

endmodule
